+            RuntimeCapability::EnvRead,
+            RuntimeCapability::ProcessSpawn,
+            RuntimeCapability::FsRead,
+            RuntimeCapability::FsWrite,
+        ];
+        for cap in &all_caps {
+            assert!(
+                require_capability(&full, *cap, "full-test").is_ok(),
+                "full should grant {:?}",
