+    #[test]
+    fn hash_sensitive_to_trace_id_change() {
+        let base = |trace: &str| {
+            EvidenceEntryBuilder::new(
+                trace,
+                "d",
+                "p",
+                SecurityEpoch::from_raw(1),
+                DecisionType::SecurityAction,
+            )
+            .chosen(ChosenAction {
+                action_name: "a".to_string(),
+                expected_loss_millionths: 0,
+                rationale: "r".to_string(),
