+            (
+                EngineObjectId([3; 32]),
+                VerificationKey::from_bytes([4; 32]),
+            ),
+            (
+                EngineObjectId([5; 32]),
+                VerificationKey::from_bytes([6; 32]),
+            ), // revoked
+        ];
+
+        let result = enforcer.check_token_batch(&tokens, "t-batch-last");
+        match result {
+            EnforcementResult::Denied(denial) => {
